const tasks = $('Fetch Tasks1').all().map(i => i.json);
const ideias = $('Fetch Ideias1').all().map(i => i.json);
const taskTitles = tasks.slice(0, 5).map(t => (t.title || t.titulo || '').substring(0, 80)).filter(Boolean).join('; ');
const ideiaTitles = ideias.slice(0, 3).map(i => (i.titulo || i.descricao || '').substring(0, 80)).filter(Boolean).join('; ');
const queryText = ('Contexto C-Suite: tarefas ' + taskTitles + ' | ideias ' + ideiaTitles).substring(0, 500) || 'Reuniao C-Suite analise operacional';
return [{ json: { queryText } }];

const res = $json;
const values = res?.embedding?.values || [];
const fallbackQuery = "SELECT content, metadata::text AS metadata, created_at FROM adv_csuite_memory ORDER BY created_at DESC LIMIT 5";
if (values.length === 0) {
  return [{ json: { memoryQuery: fallbackQuery } }];
}
const embeddingStr = '[' + values.join(',') + ']';
const memoryQuery = "SELECT content, metadata::text AS metadata, created_at FROM adv_csuite_memory WHERE embedding IS NOT NULL ORDER BY embedding <-> '" + embeddingStr.replace(/'/g, "''") + "'::vector LIMIT 5";
return [{ json: { memoryQuery } }];

const tasks = $('Fetch Tasks1').all().map(i => i.json);
const ideias = $('Fetch Ideias1').all().map(i => i.json);
const memories = $('Fetch Vector Memory1').all().map(i => i.json);
let reports = [];
try { reports = $('Fetch Founder Reports1').all().map(i => i.json); } catch (e) { reports = []; }
const currentDate = new Date().toISOString();

let contextDocs = '';
try {
  const docData = $('Fetch Context Docs1').all();
  if (Array.isArray(docData) && docData.length > 0) {
    const first = docData[0]?.json;
    if (first?.text) {
      contextDocs = first.text.substring(0, 8000);
    } else {
      contextDocs = docData.map(d => `- ${d.json?.title || 'Doc'}: ${(d.json?.content || d.json?.text || '').substring(0, 200)}`).join('\n');
    }
  }
} catch (e) {
  console.error('Erro ao processar docs:', e.message);
  contextDocs = '[Docs indisponíveis nesta execução]';
}

const docsSection = contextDocs ? `\n=== DOCUMENTOS CONTEXTUAIS ===\n${contextDocs}\n\n` : '';

const reportsText = reports.length > 0 ? reports.map(r => `- [${(r.created_at || '').substring(0, 10)}] ${r.title || 'Sem titulo'}: ${(r.content || '').substring(0, 500)}`).join('\n') : 'Nenhum relatorio do founder nos ultimos 7 dias.';
const founderSection = `\n=== RELATORIOS DO FOUNDER (ultimos 7 dias) ===\n${reportsText}\n\n`;

const isTech = (t) => /(bug|dev|api|banco|sql|deploy|tech|codigo|app|web)/i.test((t.title || '') + (t.description || ''));
const tasksTech = tasks.filter(isTech);

const formatTasks = (list) => list.length > 0 ? list.map(t => `- [${t.status || 'N/A'}] ${t.title || t.titulo || 'N/A'}`).join('\n') : 'Nenhuma.';
const memText = memories.length > 0 ? memories.map(m => `- ${m.content}`).join('\n') : 'Nenhuma.';

const baseContext = `DATA: ${currentDate}${docsSection}${founderSection}=== MEMORIA C-SUITE ===\n${memText}\n`;
const contextCTO = baseContext + '\n=== TAREFAS TECH ===\n' + formatTasks(tasksTech);
const context = baseContext + '\n=== RESUMO GERAL ===\n' + formatTasks(tasks);

return [{ json: { context, contextCTO, runTimestamp: currentDate, tasksCount: tasks.length, ideasCount: ideias.length } }];

// Fase 2: Validação e auditoria dos outputs dos C-Levels
function getRaw(nodeName, type) {
  try {
    const d = $(nodeName).first().json;
    if (type === 'agent') return d?.output || d?.text || d?.body || null;
    return d?.candidates?.[0]?.content?.parts?.[0]?.text || d?.text || d?.body || null;
  } catch (e) { return null; }
}
function validateContent(raw) {
  if (!raw || String(raw).trim() === '') return { valid: false, reason: 'vazio' };
  try {
    const s = String(raw).trim();
    if (s.startsWith('{') || s.startsWith('[')) JSON.parse(s);
    return { valid: true };
  } catch (e) { return { valid: true }; }
}
const runTs = $('Build Context1').first().json.runTimestamp;
const audit = {
  cfo: validateContent(getRaw('CFO Agent Buffett1', 'agent')),
  cto: validateContent(getRaw('CTO Agent Torvalds1', 'agent')),
  coo: validateContent(getRaw('COO Ohno1', 'agent')),
  cmo: validateContent(getRaw('CMO Ogilvy1', 'agent')),
  cpo: validateContent(getRaw('CPO Cagan1', 'agent'))
};
const allValid = Object.values(audit).every(a => a.valid);
const invalid = Object.entries(audit).filter(([,a]) => !a.valid).map(([k]) => k);
if (invalid.length > 0) {
  console.warn('[Validate Outputs] C-Levels com output inválido:', invalid.join(', '), '| Run:', runTs);
}
return [{ json: { validationAudit: audit, allValid, invalid, auditTimestamp: new Date().toISOString(), runTimestamp: runTs } }];

function getSafeOutput(nodeName) {
  try {
    const data = $(nodeName).first().json;
    return data?.output || data?.text || data?.body || JSON.stringify(data);
  } catch (e) {
    return `[Erro] ${nodeName}: ${e.message}`;
  }
}

const context = $('Build Context1').first().json.context;
const runTimestamp = $('Build Context1').first().json.runTimestamp;
const validationAudit = $('Validate Outputs1').first().json?.validationAudit || {};

const cfoReport = getSafeOutput('CFO Agent Buffett1');
const ctoReport = getSafeOutput('CTO Agent Torvalds1');
const cooReport = getSafeOutput('COO Ohno1');
const cmoReport = getSafeOutput('CMO Ogilvy1');
const cpoReport = getSafeOutput('CPO Cagan1');

const compiledReport = [
  '=== RELATORIO CFO — Warren Buffett ===', cfoReport, '',
  '=== RELATORIO CTO — Linus Torvalds ===', ctoReport, '',
  '=== RELATORIO COO — Taiichi Ohno ===', cooReport, '',
  '=== RELATORIO CMO — David Ogilvy ===', cmoReport, '',
  '=== RELATORIO CPO — Marty Cagan ===', cpoReport
].join('\n');

if (!compiledReport || compiledReport.trim().length === 0) {
  throw new Error('Relatório compilado vazio! Verifique os agentes.');
}

return [{ 
  json: { 
    compiledReport, 
    context, 
    runTimestamp, 
    cfoReport, 
    ctoReport, 
    cooReport, 
    cmoReport, 
    cpoReport,
    validationAudit,
    reportGenerated: true
  } 
}];

function extractGeminiText(nodeName) {
  try {
    const r = $(nodeName).first().json;
    return r.candidates[0].content.parts[0].text;
  } catch(e) {
    return null;
  }
}

const ceoRaw = $json.candidates?.[0]?.content?.parts?.[0]?.text || "";
const runTimestamp = $('Build Context1').first().json.runTimestamp;
const compiledReport = $('Compile C-Level Reports1').first().json.compiledReport;

// Remove markdown code block se existir (```json ... ``` ou ``` ... ```)
let jsonStr = ceoRaw.trim();
const jsonMatch = jsonStr.match(/```(?:json)?\s*([\s\S]*?)```/);
if (jsonMatch) jsonStr = jsonMatch[1].trim();

let ceoDecision = {};
try {
  ceoDecision = JSON.parse(jsonStr || '{}');
} catch(e) {
  ceoDecision = {
    resumo_executivo: ceoRaw || 'Análise automática do C-Suite concluída.',
    decisoes: [],
    titulo_issue_github: 'C-Suite Review — ' + runTimestamp.substring(0, 10),
    descricao_issue_github: '## Revisão Automática do C-Suite\n\n' + (ceoRaw || 'Sem detalhes disponíveis.'),
    mensagem_google_chat: 'C-Suite concluiu análise autónoma. Verifique o GitHub para detalhes.'
  };
}

// Normalizar chaves em inglês para português
if (!ceoDecision.resumo_executivo && ceoDecision.executive_summary) ceoDecision.resumo_executivo = ceoDecision.executive_summary;
if ((!ceoDecision.decisoes || !ceoDecision.decisoes.length) && ceoDecision.decisions?.length) ceoDecision.decisoes = ceoDecision.decisions;
if (!ceoDecision.titulo_issue_github && ceoDecision.issue_title) ceoDecision.titulo_issue_github = ceoDecision.issue_title;
if (!ceoDecision.descricao_issue_github && ceoDecision.issue_description) ceoDecision.descricao_issue_github = ceoDecision.issue_description;
if (!ceoDecision.mensagem_google_chat && ceoDecision.chat_message) ceoDecision.mensagem_google_chat = ceoDecision.chat_message;

// Validação crítica
if (!ceoDecision.descricao_issue_github || ceoDecision.descricao_issue_github.trim().length === 0) {
  throw new Error('CEODecision vazia! Verifique a resposta do CEO Grove.');
}

const issueTitle = (ceoDecision.titulo_issue_github || ('C-Suite Review — ' + runTimestamp.substring(0, 10))).substring(0, 256);

const issueBody = ceoDecision.descricao_issue_github ||
  '## Resumo Executivo\n\n' + (ceoDecision.resumo_executivo || 'Sem resumo.') +
  '\n\n## Decisões\n\n' + (JSON.stringify(ceoDecision.decisoes || [], null, 2)) +
  '\n\n---\n*Gerado automaticamente pelo C-Suite Loop — Adventure Labs OS*\n*Run: ' + runTimestamp + '*';

const chatMessage = ceoDecision.mensagem_google_chat || 'C-Suite Loop concluído. Verifique o GitHub.';
const summaryText = ceoDecision.resumo_executivo || issueTitle;

return [{ json: {
  ...ceoDecision,
  issueTitle,
  issueBody,
  chatMessage,
  summaryText,
  runTimestamp,
  compiledReport,
  readyForGitHub: true
} }];

